/**
 * Verify Email Page
 * 
 * Handles email verification via token from verification links. Validates
 * tokens, user types, and processes email verification. Handles malformed
 * URL parameters gracefully.
 */

import React, { useEffect, useMemo, useState, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { authService } from '@/features/auth/services/coreAuthService.js';
import { LanguageSelector } from '@/shared/components';
import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';
import logger from '@/shared/utils/logger.js';

const VerifyEmailPage = () => {
  const { t } = useTranslation();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { effectiveTheme } = useTheme();
  const [status, setStatus] = useState('loading'); // Always start with loading
  const [message, setMessage] = useState('');
  const [hasVerified, setHasVerified] = useState(false);
  const isVerifyingRef = useRef(false); // Prevent multiple simultaneous calls
  const [isLoading, setIsLoading] = useState(true); // Track if API call is in progress

  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;

  const normalizedParams = useMemo(() => {
    const raw = window.location.search || '';
    const fixed = raw.replace(/(token=[^&?#]+)\?/, '$1&');
    const sp = new URLSearchParams(fixed);
    // URLSearchParams automatically decodes the token, but ensure it's trimmed
    let token = (sp.get('token') || '').trim();
    // If token appears to be URL-encoded, decode it (though URLSearchParams should handle this)
    if (token && token.includes('%')) {
      try {
        token = decodeURIComponent(token);
      } catch (e) {
        logger.warn('Failed to decode token', { error: e });
      }
    }
    const usertype = (sp.get('usertype') || '').toLowerCase();
    const email = sp.get('email') || '';
    logger.debug('Extracted token from URL', { tokenLength: token.length, tokenPreview: token.substring(0, 30) + '...', usertype, email });
    return { token, usertype, email };
  }, [searchParams]);

  useEffect(() => {
    const { token, usertype, email } = normalizedParams;

    // Prevent multiple calls - if already verified or currently verifying, return early
    if (hasVerified || isVerifyingRef.current) {return;}

    if (!token) {
      setStatus('error');
      setMessage(t('invalidVerificationLink', { ns: 'auth' }));
      return;
    }

    if (!['customer', 'business_contact'].includes(usertype)) {
      setStatus('error');
      setMessage(t('invalidUserType', { ns: 'auth' }));
      return;
    }

    // Mark as verifying to prevent duplicate calls
    isVerifyingRef.current = true;
    setIsLoading(true); // Ensure loading state is set

    const verifyEmail = async () => {
      try {
        // Wait for API response before proceeding
        const { success, message, data } = await authService.verifyEmail(token, usertype);

        // API response received - now update UI
        setIsLoading(false);

        if (success) {
          // Success -> redirect to success page with usertype
          setHasVerified(true);
          setStatus('success');
          isVerifyingRef.current = false; // Reset before navigation
          navigate('/email-verified', {
            replace: true,
            state: {
              usertype,
              email: email || ''
            }
          });
        } else {
          // API returned an error (invalid token, expired, etc.)
          // Show friendly error message
          setStatus('error');
          isVerifyingRef.current = false;
        }
      } catch (error) {
        logger.error('Email verification error', { error });
        // API response received (even if error) - now update UI
        setIsLoading(false);
        setStatus('error');
        // Check if this is a known error we can handle gracefully
        if (error.isRefreshTokenDeleteError || error.message?.includes('refreshToken.delete')) {
          // Even if there was a refresh token cleanup issue, we can still proceed
          setHasVerified(true);
          setStatus('success');
          isVerifyingRef.current = false; // Reset before navigation
          navigate('/email-verified', {
            replace: true,
            state: {
              usertype,
              email: email || ''
            }
          });
        } else {
          // Any other error (invalid token, network error, etc.) - show friendly message
          setStatus('error');
          isVerifyingRef.current = false; // Reset on error
        }
      }
    };

    verifyEmail();
  }, [normalizedParams.token, normalizedParams.usertype, normalizedParams.email, navigate, hasVerified, t]);

  // Get the first part of the email for personalization
  const getEmailPrefix = () => {
    const email = normalizedParams.email || '';
    return email.split('@')[0] || 'User';
  };

  return (
    <div className="login-container">
      <div className="login-form" style={{ position: 'relative' }}>
        {/* Language Selector */}
        <div style={{
          position: 'absolute',
          top: '20px',
          right: '20px',
          zIndex: 10,
        }}>
          <LanguageSelector />
        </div>
        <img
          src={logoSrc}
          alt="iSmartPay Logo"
          className="login-logo"
          style={{
            transition: 'opacity var(--transition-theme)',
            opacity: 1
          }}
        />

        {(status === 'loading' || isLoading) && (
          <div style={{ textAlign: 'center', padding: '32px 0' }}>
            <div style={{
              width: '64px',
              height: '64px',
              border: '4px solid #e5e7eb',
              borderTop: '4px solid #004895',
              borderRadius: '50%',
              animation: 'spin 1s linear infinite',
              margin: '0 auto 24px'
            }} />
            <h2 style={{ fontSize: '1.75rem', fontWeight: 700, color: '#1a202c', marginBottom: '8px' }}>{t('verifyingYourEmail', { ns: 'auth' })}</h2>
            <p style={{ color: '#6b7280' }}>{t('pleaseWaitVerifying', { ns: 'auth' })}</p>
          </div>
        )}

        {status === 'success' && (
          <div style={{ textAlign: 'center', padding: '32px 0' }}>
            <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '24px' }}>
              <div style={{
                backgroundColor: '#d1fae5',
                padding: '16px',
                borderRadius: '50%',
                width: '64px',
                height: '64px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center'
              }}>
                <svg style={{ width: '32px', height: '32px', color: '#10b981' }} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                </svg>
              </div>
            </div>
            <h2 style={{ fontSize: '1.75rem', fontWeight: 700, color: '#1a202c', marginBottom: '12px' }}>{t('emailVerifiedSuccessfully', { ns: 'auth' })}</h2>
            <p style={{ color: '#6b7280', marginBottom: '32px' }}>
              {t('emailVerifiedCanSignIn', { ns: 'auth' })}
            </p>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <button
                onClick={() => navigate('/login')}
              >
                {t('continueToLogin', { ns: 'auth' })}
              </button>
              <button
                onClick={() => navigate('/')}
                style={{ backgroundColor: '#6b7280' }}
              >
                {t('backToHome', { ns: 'auth' })}
              </button>
            </div>
          </div>
        )}

        {status === 'error' && (
          <div style={{ textAlign: 'center', padding: '32px 0' }}>
            <div style={{
              margin: '0 auto 24px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              width: '80px',
              height: '80px',
              borderRadius: '50%',
              backgroundColor: '#fef3c7'
            }}>
              <span className="material-symbols-outlined" style={{ fontSize: '48px', color: '#f59e0b' }}>
                sentiment_satisfied
              </span>
            </div>
            <h2 style={{ fontSize: '1.75rem', fontWeight: 700, color: '#1a202c', marginBottom: '16px' }}>
              {t('verificationLinkExpired', { ns: 'auth', defaultValue: 'Verification Link Expired' })}
            </h2>
            <div style={{
              backgroundColor: '#fffbeb',
              border: '1px solid #fde68a',
              borderRadius: '10px',
              padding: '16px',
              marginBottom: '24px',
              color: '#92400e',
              textAlign: 'center',
              fontSize: '0.95rem',
              lineHeight: '1.6'
            }}>
              <p style={{ margin: 0 }}>
                {t('dontWorryVerification', {
                  ns: 'auth',
                  defaultValue: "Don't worry! You can verify your email from the verification page in Settings after logging in."
                })}
              </p>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <button
                onClick={() => navigate('/login')}
                style={{ width: '100%' }}
              >
                {t('goToLogin', { ns: 'auth', defaultValue: 'Go to Login' })}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default VerifyEmailPage;
